sql:
SELECT * 
FROM data_entries 
WHERE user_id = 1;

SELECT scientific_name 
FROM taxa 
WHERE taxon_id = 1;

SELECT scientific_name, classification
FROM taxa
WHERE classification = 'Animalia';

SELECT interaction_description 
FROM interaction_types 
WHERE interaction_type_id IN (SELECT interaction_type_id FROM interactions);

SELECT ecosystem_name, geographic_coordinates
FROM ecosystems
WHERE ecosystem_type = 'forest';

external_knowledge:
- 'threatened creatures' refers to taxa with a conservation status of 'endangered';
- 'prey' refers to species involved in 'eatenBy' interactions;
- 'vast Sahara' indicates the location ‘Sahara Desert’.

sql:
SELECT interaction_description
FROM interaction_types
WHERE interaction_category = 'trophic';

SELECT taxon_id, scientific_name, common_name, classification
FROM taxa
WHERE taxon_id > 100 AND taxon_id < 200;

SELECT scientific_name, common_name, classification, image_url
FROM taxa
WHERE common_name LIKE '%Vireo%' AND habitat = 'Forest';
